class Solution:
    def rectangleArea(self, rectangles):
        MOD = 10**9 + 7
        ys = sorted(set([r[1] for r in rectangles] + [r[3] for r in rectangles]))
        yidx = {y: i for i, y in enumerate(ys)}
        events = []
        for x1, y1, x2, y2 in rectangles:
            events.append((x1, y1, y2, 1))
            events.append((x2, y1, y2, -1))
        events.sort()
        count = [0] * (len(ys) - 1) if len(ys) > 1 else []
        total = 0
        prev_x = events[0][0]
        i = 0
        n = len(events)
        while i < n:
            x = events[i][0]
            covered = 0
            for j in range(len(ys) - 1):
                if count[j] > 0:
                    covered += ys[j + 1] - ys[j]
            total += covered * (x - prev_x)
            prev_x = x
            while i < n and events[i][0] == x:
                _, y1, y2, sign = events[i]
                for j in range(yidx[y1], yidx[y2]):
                    count[j] += sign
                i += 1
        return total % MOD

