var rectangleArea = function(rectangles) {
    const MOD = 1000000007n;
    const ySet = new Set();
    for (const r of rectangles) { ySet.add(r[1]); ySet.add(r[3]); }
    const ys = [...ySet].sort((a, b) => a - b);
    const yidx = new Map();
    ys.forEach((y, i) => yidx.set(y, i));
    const events = [];
    for (const [x1, y1, x2, y2] of rectangles) {
        events.push([x1, y1, y2, 1]);
        events.push([x2, y1, y2, -1]);
    }
    events.sort((a, b) => a[0] - b[0]);
    const count = new Array(Math.max(0, ys.length - 1)).fill(0);
    let total = 0n;
    let prevX = events[0][0];
    let i = 0;
    const n = events.length;
    while (i < n) {
        const x = events[i][0];
        let covered = 0n;
        for (let j = 0; j < ys.length - 1; j++) {
            if (count[j] > 0) covered += BigInt(ys[j + 1] - ys[j]);
        }
        total += covered * BigInt(x - prevX);
        prevX = x;
        while (i < n && events[i][0] === x) {
            const [, y1, y2, sign] = events[i];
            for (let j = yidx.get(y1); j < yidx.get(y2); j++) count[j] += sign;
            i++;
        }
    }
    return Number(total % MOD);
};
